                            scale: 0.82,
                            rotateX: -8,
                            filter: 'blur(5px)'
                          },
                          visible: {
                            opacity: 1,
                            x: 0,
                            y: 0,
                            scale: 1,
                            rotateX: 0,
                            filter: 'blur(0px)',
                            transition: {
                              type: 'spring',
                              stiffness: 380,
                              damping: 22,
                              mass: 0.55,
                              filter: {
                                duration: 0.28,
                                ease: [0.25, 0.1, 0.25, 1]
