63	const RefreshI = () => <Icon><path d="M3 12a9 9 0 0 1 15.5-6.4L21 8" /><path d="M21 3v5h-5" /><path d="M21 12a9 9 0 0 1-15.5 6.4L3 16" /><path d="M3 21v-5h5" /></Icon>;
64	const CloseI = () => <Icon><path d="M6 6l12 12" /><path d="M6 18 18 6" /></Icon>;
65	const ArrowL = () => <Icon><path d="M15 6l-6 6 6 6" /></Icon>;
66	const ArrowR = () => <Icon><path d="M9 6l6 6-6 6" /></Icon>;
67	// ─── description ──────────────────────────────────────────────────────
68	const Description = ({ text }: { text: string }) => (
69	  <div className={styles.description}>
70	    <h3>Description</h3>
71	    <p>{text}</p>
72	  </div>
73	);
74	
75	// ─── mosaic gallery ────────────────────────────────────────────────────
76	const Gallery = ({
77	  images,
78	  activeIdx,
79	  setActiveIdx,
80	  onOpenLightbox,
81	  productTitle,
82	}: {
83	  images: string[];
84	  activeIdx: number;
85	  setActiveIdx: (i: number) => void;
86	  onOpenLightbox: (i: number) => void;
87	  productTitle: string;
88	}) => {
89	  // Pointer/swipe state — refs avoid re-renders on every move.
90	  const dragStartRef = useRef<number | null>(null);
91	  const justSwipedRef = useRef(false);
92	  const lastInteractionRef = useRef(0);
93	  const activeIdxRef = useRef(activeIdx);
94	  useEffect(() => { activeIdxRef.current = activeIdx; }, [activeIdx]);
95	
96	  // Auto-advance: every ~4.5s, switch to a random different image. Pauses
97	  // for 6s after any user interaction so swipes/clicks aren't fought by
98	  // the timer.
99	  useEffect(() => {
100	    if (images.length < 2) return;
101	    const id = setInterval(() => {
102	      if (performance.now() - lastInteractionRef.current < 6000) return;
103	      const cur = activeIdxRef.current;
104	      let next = cur;
105	      while (next === cur) next = Math.floor(Math.random() * images.length);
106	      setActiveIdx(next);
107	    }, 4500);
108	    return () => clearInterval(id);
109	  }, [images.length, setActiveIdx]);
110	
111	  const onPointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
112	    dragStartRef.current = e.clientX;
113	    lastInteractionRef.current = performance.now();
114	  };
115	  const onPointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
116	    if (dragStartRef.current == null) return;
117	    if (Math.abs(e.clientX - dragStartRef.current) > 10) {
118	      // Capture so the gesture survives leaving a child element.
119	      try { (e.currentTarget as HTMLElement).setPointerCapture(e.pointerId); } catch { /* noop */ }
120	    }
121	  };
122	  const onPointerUp = (e: React.PointerEvent<HTMLDivElement>) => {
123	    const start = dragStartRef.current;
124	    dragStartRef.current = null;
125	    if (start == null) return;
126	    const dx = e.clientX - start;
127	    lastInteractionRef.current = performance.now();
128	    if (Math.abs(dx) > 50 && images.length > 1) {
129	      const dir = dx < 0 ? 1 : -1;
130	      const n = images.length;
131	      setActiveIdx((activeIdxRef.current + dir + n) % n);
132	      // Suppress the trailing click on the card we just dragged across.
133	      justSwipedRef.current = true;
134	      setTimeout(() => { justSwipedRef.current = false; }, 50);
135	    }
136	  };
137	  const onPointerCancel = () => { dragStartRef.current = null; };
138	
139	  if (images.length === 0) return null;
140	
141	  return (
142	    <div className={styles.gallery}>
143	      <div
144	        className={styles.mosaicStack}
145	        onPointerDown={onPointerDown}
146	        onPointerMove={onPointerMove}
147	        onPointerUp={onPointerUp}
148	        onPointerCancel={onPointerCancel}
149	      >
150	        {images.map((src, i) => {
151	          const offset = i - activeIdx;
152	          const isActive = i === activeIdx;
153	          // Skip cards fully outside the visible stack window — they paint
154	          // at opacity 0 anyway, and rendering them keeps GPU layers alive
155	          // for nothing.
156	          if (Math.abs(offset) > 2) return null;
157	          return (
158	            <div
159	              key={`${src}-${i}`}
160	              className={`${styles.mosCard} ${isActive ? styles.mosCardActive : ''}`}
161	              onClick={() => {
162	                if (justSwipedRef.current) return;
163	                if (isActive) onOpenLightbox(i);
164	                else setActiveIdx(i);
165	              }}
166	              style={{
167	                transform: `translate(${offset * 22}px, ${Math.abs(offset) * 18}px) scale(${1 - Math.abs(offset) * 0.06}) rotate(${offset * 1.5}deg)`,
168	                zIndex: 10 - Math.abs(offset),
169	                opacity: isActive ? 1 : 0.6,
170	                cursor: isActive ? 'zoom-in' : 'pointer',
171	              }}
172	            >
173	              <img src={src} alt={isActive ? productTitle : ''} loading={isActive ? 'eager' : 'lazy'} decoding="async" draggable={false} />
174	              {isActive && (
175	                <>
176	                  <div className={styles.frameCounter}>
177	                    {String(i + 1).padStart(2, '0')} / {String(images.length).padStart(2, '0')}
178	                  </div>
179	                  {VIEW_LABELS[i] && <div className={styles.viewTag}>{VIEW_LABELS[i]}</div>}
180	                </>
181	              )}
182	            </div>
183	          );
184	        })}
185	      </div>
186	      <div className={styles.mosaicScrubber}>
187	        {images.map((_, i) => (
188	          <button
189	            key={i}
190	            type="button"
191	            className={`${styles.scrubDot} ${i === activeIdx ? styles.scrubDotActive : ''}`}
192	            onClick={() => {
193	              lastInteractionRef.current = performance.now();
194	              setActiveIdx(i);
195	            }}
196	            aria-label={`View ${i + 1}`}
197	          >
198	            <span className={styles.scrubNum}>{String(i + 1).padStart(2, '0')}</span>
199	            <span className={styles.scrubLine}>
200	              <NavLinkGLSLCanvas isHovered={i === activeIdx} inline width={160} height={16} />
201	            </span>
202	          </button>
203	        ))}
204	      </div>
205	    </div>
206	  );
207	};
208	
209	// ─── material story ───────────────────────────────────────────────────
210	const MaterialStory = ({ className = '' }: { className?: string }) => (
211	  <section className={`${styles.materialStory} ${className}`.trim()}>
212	    <div className={styles.msInner}>
213	      <img className={styles.msPeacock} src="/theme_images/peacock-art-white.png" alt="" aria-hidden="true" />
214	      <div className={styles.msEyebrow}><span className={styles.eyebrowGlyph} /> The Stone</div>
215	      <h3 className={styles.msTitle}>
216	        Quarried near Tadipatri,<br />chiselled by hand.
217	      </h3>
218	      <p className={styles.msBody}>
219	        The block was lifted from the Andhra granite belt — a stone so dense it rings when struck.
220	        Patient relief work follows: shaping the silhouette, drawing the brow, deepening the gaze.
221	        No two pieces leave the atelier identical.
222	      </p>
223	      <div className={styles.msStats}>
224	        <div><span className={styles.msNum}>2.74</span><span className={styles.msCap}>g/cm³ density</span></div>
225	        <div><span className={styles.msNum}>90+</span><span className={styles.msCap}>days in carving</span></div>
226	        <div><span className={styles.msNum}>∞</span><span className={styles.msCap}>generational</span></div>
227	      </div>
228	    </div>
229	  </section>
230	);
231	
232	// ─── trust strip ──────────────────────────────────────────────────────
233	const CraftStrip = () => {
234	  const items = [
235	    { icon: <ShieldI />, t: 'Authenticated', s: 'Hand-signed by the master carver' },
236	    { icon: <TruckI />, t: 'Insured shipping', s: 'Crated, padded and tracked' },
237	    { icon: <RefreshI />, t: '7-day returns', s: 'If the form does not move you' },
238	  ];
239	  return (
240	    <div className={styles.craftStrip}>
241	      <div className={styles.csInner}>
242	        {items.map((it, i) => (
243	          <div key={i} className={styles.csItem}>
244	            <span className={styles.csIcon}>{it.icon}</span>
245	            <div>
246	              <div className={styles.csTitle}>{it.t}</div>
247	              <div className={styles.csSub}>{it.s}</div>
248	            </div>
249	          </div>
250	        ))}
251	      </div>
252	    </div>
253	  );
254	};
255	
256	// ─── lightbox ─────────────────────────────────────────────────────────
257	const Lightbox = ({
258	  open, idx, images, onClose, onPrev, onNext,
259	}: {
260	  open: boolean;
261	  idx: number;
262	  images: string[];
263	  onClose: () => void;
264	  onPrev: () => void;
265	  onNext: () => void;
266	}) => {
267	  useEffect(() => {
268	    if (!open) return;
269	    const onKey = (e: KeyboardEvent) => {
270	      if (e.key === 'Escape') onClose();
271	      else if (e.key === 'ArrowLeft') onPrev();
272	      else if (e.key === 'ArrowRight') onNext();
273	    };
274	    window.addEventListener('keydown', onKey);
275	    return () => window.removeEventListener('keydown', onKey);
276	  }, [open, onClose, onPrev, onNext]);
277	
278	  // Skip rendering entirely when closed — the previous version kept the
279	  // dialog DOM mounted with display:none, which still cost layout/parse work.
280	  if (!open) return null;
281	  return (
282	    <div className={`${styles.lightbox} ${styles.lightboxOpen}`} role="dialog" aria-modal="true">
283	      <button className={`${styles.lbBtn} ${styles.lbClose}`} onClick={onClose} aria-label="Close"><CloseI /></button>
284	      <button className={`${styles.lbBtn} ${styles.lbPrev}`} onClick={onPrev} aria-label="Previous"><ArrowL /></button>
285	      <button className={`${styles.lbBtn} ${styles.lbNext}`} onClick={onNext} aria-label="Next"><ArrowR /></button>
286	      {images[idx] && <img src={images[idx]} alt="" />}
287	      <div className={styles.lbCounter}>
288	        {String(idx + 1).padStart(2, '0')} / {String(images.length).padStart(2, '0')}
289	      </div>
290	    </div>
291	  );
292	};
293	
294	// ─── main component ───────────────────────────────────────────────────
295	export default function ProductDetailPage({ params }: ProductDetailPageProps) {
296	  const [handle, setHandle] = useState<string | null>(null);
297	  const { addToCart, loading: cartLoading } = useCart();
298	  const { isInWishlist, toggleWishlist, pendingIds: wishPending, isAuthenticated: wishAuth } = useWishlist();
299	
300	  const [state, setState] = useState<PageState>({
301	    product: null,
302	    productData: null,
303	    loading: true,
304	    error: null,
305	    isAddingToCart: false,
306	    addToCartSuccess: false,
307	    addToCartError: null,
308	  });
309	  const [qty, setQty] = useState(1);
310	  const [activeIdx, setActiveIdx] = useState(0);
311	  const [lightbox, setLightbox] = useState<{ open: boolean; idx: number }>({ open: false, idx: 0 });
312	
313	  const isMounted = useRef(true);
314	  useEffect(() => {
315	    isMounted.current = true;
316	    return () => { isMounted.current = false; };
317	  }, []);
318	
319	  const update = useCallback((u: Partial<PageState>) => {
320	    if (!isMounted.current) return;
321	    setState(prev => ({ ...prev, ...u }));
322	  }, []);
323	
324	  const { retryCount, isRetrying, canRetry, retry, reset } = useRetry({
325	    maxRetries: 3, initialDelay: 1000, backoffMultiplier: 2, maxDelay: 10000,
326	  });
327	
328	  // resolve route params
329	  useEffect(() => {
330	    params.then(p => {
331	      if (!isValidHandle(p.handle)) { notFound(); return; }
332	      setHandle(p.handle);
333	    });
334	  }, [params]);
335	
336	  const fetchProduct = useCallback(async () => {
337	    if (!handle) return;
338	    try {
339	      update({ loading: true, error: null, addToCartError: null, addToCartSuccess: false });
340	      try {
341	        const [productData, rawProduct] = await Promise.all([
342	          productsService.fetchProductByHandle(handle),
343	          medusaApiClient.getProductByHandle(handle),
344	        ]);
345	        if (!isMounted.current) return;
346	        update({ productData, product: rawProduct, loading: false });
347	        reset();
348	      } catch (handleError) {
349	        // Fall back: search all products by generated handle
350	        const all = await productsService.fetchProducts();
351	        const match = all.find(p => generateProductHandle(p.title) === handle);
352	        if (!match) { notFound(); return; }
353	        let rawProduct: Product | null = null;
354	        try { rawProduct = await medusaApiClient.getProduct(match.id); } catch { /* tolerated */ }
355	        if (!isMounted.current) return;
356	        update({ productData: match, product: rawProduct, loading: false });
357	        reset();
358	      }
359	    } catch (err) {
360	      if (!isMounted.current) return;
361	      const e = err as ProductsServiceError;
362	      if (e.type === 'api' && e.originalError && 'status' in e.originalError && (e.originalError as any).status === 404) {
363	        notFound(); return;
364	      }
365	      update({ error: e, loading: false });
366	    }
367	  }, [handle, update, reset]);
368	
369	  useEffect(() => { if (handle) fetchProduct(); }, [handle, fetchProduct]);
370	
371	  const handleRetry = useCallback(async () => {
372	    if (!canRetry || !isMounted.current) return;
373	    try { await retry(fetchProduct); } catch { /* error handled inside */ }
374	  }, [retry, fetchProduct, canRetry]);
375	
376	  // build gallery image list from real product data
377	  const images = useMemo(() => {
378	    const out: string[] = [];
379	    const seen = new Set<string>();
380	    const push = (u?: string | null) => {
381	      if (!u) return;
382	      if (seen.has(u)) return;
383	      seen.add(u);
384	      out.push(u);
385	    };
386	    if (state.product?.images?.length) {
387	      state.product.images.forEach(img => push(img.url));
388	    }
389	    push(state.productData?.foregroundImage);
390	    push(state.productData?.backgroundImage);
391	    return out;
392	  }, [state.product, state.productData]);
393	
394	  // keep active index in range when images change
395	  useEffect(() => {
396	    if (activeIdx >= images.length && images.length > 0) setActiveIdx(0);
397	  }, [images.length, activeIdx]);
398	
399	  // ─── add to cart (mirrors original logic) ────────────────────────
400	  const handleAddToCart = useCallback(async () => {
401	    if (!addToCart || !state.productData || !state.product) return;
402	
403	    if (!state.productData.inStock) {
404	      const allowBackorder = state.productData.inventory?.allowBackorder;
405	      if (!allowBackorder) {
406	        update({ addToCartError: 'This product is currently out of stock.', addToCartSuccess: false });
407	        return;
408	      }
409	    }
410	    if (!state.product.variants?.length) {
411	      update({ addToCartError: 'This product has no available variants.', addToCartSuccess: false });
412	      return;
413	    }
414	
415	    let selectedVariant = null;
416	    for (const v of state.product.variants) {
417	      let hasStock = false;
418	      if (typeof v.inventory_quantity === 'number' && v.inventory_quantity > 0) hasStock = true;
419	      else if (v.inventory_items?.length) {
420	        let avail = 0;
421	        for (const ii of v.inventory_items) {
422	          for (const lvl of ii.inventory?.location_levels || []) avail += lvl?.available_quantity || 0;
423	        }
424	        hasStock = avail >= qty;
425	      } else if (!v.manage_inventory) hasStock = true;
426	      else if (v.manage_inventory && state.productData.inStock) hasStock = true;
427	      if (!hasStock && v.allow_backorder) hasStock = true;
428	      if (hasStock) { selectedVariant = v; break; }
429	    }
430	    if (!selectedVariant) {
431	      update({ addToCartError: 'No product variant with sufficient stock is available.', addToCartSuccess: false });
432	      return;
433	    }
434	
435	    update({ isAddingToCart: true, addToCartError: null, addToCartSuccess: false });
436	    try {
437	      let estimatedUnitPrice: number | undefined;
438	      if (selectedVariant.prices?.length) {
439	        estimatedUnitPrice = Number(selectedVariant.prices[0].amount || 0) / 100;
440	      }
441	      await addToCart(selectedVariant.id, qty, estimatedUnitPrice);
442	      update({ addToCartSuccess: true });
443	      setTimeout(() => update({ addToCartSuccess: false }), 3000);
444	    } catch (err) {
445	      let msg = 'Failed to add item to cart. Please try again.';
446	      if (err instanceof Error) {
447	        if (err.message.includes('out of stock') || err.message.includes('insufficient stock')) {
448	          msg = 'This item is currently out of stock or has insufficient quantity available.';
449	        } else if (err.message.includes('cart not found')) {
450	          msg = 'Your cart session has expired. Please refresh the page and try again.';
451	        } else msg = err.message;
452	      }
453	      update({ addToCartError: msg });
454	      setTimeout(() => update({ addToCartError: null }), 5000);
455	    } finally {
456	      update({ isAddingToCart: false });
457	    }
458	  }, [addToCart, state.product, state.productData, qty, update]);
459	
460	  // ─── render: handle resolution ───────────────────────────────────
461	  if (!handle) {
462	    return (
463	      <div className={styles.stateWrap}>
464	        <div>
465	          <h1 className={styles.stateTitle}>Loading…</h1>
466	        </div>
467	      </div>
468	    );
469	  }
470	
471	  if (state.loading || isRetrying) {
472	    return (
473	      <div className={styles.stateWrap}>
474	        <div>
475	          <LoadingSpinner size="medium" color="primary" />
476	          <p className={styles.stateMsg} style={{ marginTop: '1rem' }}>Loading product…</p>
477	        </div>
478	      </div>
479	    );
480	  }
481	
482	  if (state.error) {
483	    return (
484	      <div className={styles.stateWrap}>
485	        <div>
486	          <h1 className={styles.stateTitle}>Error Loading Product</h1>
487	          <p className={styles.stateMsg}>{state.error.message}</p>
488	          {canRetry && (
489	            <button className={styles.retryBtn} onClick={handleRetry}>
490	              Try Again {retryCount > 0 && `(${retryCount}/3)`}
491	            </button>
492	          )}
493	        </div>
494	      </div>
495	    );
496	  }
497	
498	  if (!state.productData) { notFound(); return null; }
499	
500	  const product = state.productData;
501	  const rawProduct = state.product;
502	  const currency = product.currency || 'INR';
503	  const fmt = (n?: number) => (typeof n === 'number'
504	    ? (currency === 'INR' ? `₹ ${n.toLocaleString('en-IN')}` : `${currency} ${n.toLocaleString()}`)
505	    : '—');
506	  const savePct = product.originalPrice && product.price && product.originalPrice > product.price
507	    ? Math.round(((product.originalPrice - product.price) / product.originalPrice) * 100)
508	    : 0;
509	
510	  const inWishlist = !!(rawProduct && isInWishlist(rawProduct.id));
511	  const wishlistBusy = !!(rawProduct && wishPending.has(rawProduct.id));
512	
513	  return (
514	    <div className={styles.pdp}>
515	      <div className={styles.pdpBg} aria-hidden="true">
516	        {/* Each art's spotlight rims its INNER (page-facing) edge:
517	              right-of-page arts (peacock, elephant) → light runs down their LEFT side
518	              left-of-page arts  (mandala, lakshmi)  → light runs down their RIGHT side
519	            so the highlight always travels toward the reader's gaze, not off the screen.
520	            spotlightFilter is the vivid filter for the revealed copy; the dim base
521	            stays at the toned-down filter set on .bgImg in the module CSS. */}
522	        <DynamicSvgEffect
523	          className={`${styles.bgArt} ${styles.bgPeacock}`}
524	          effect="spotlight"
525	          rimSide="left"
526	          spotlightFilter="grayscale(100%) contrast(1.18) brightness(0.45)"
527	        >
528	          <img className={styles.bgImg} src="/theme_images/peacock-art-white.png" alt="" />
529	        </DynamicSvgEffect>
530	        <DynamicSvgEffect
531	          className={`${styles.bgArt} ${styles.bgMandala}`}
532	          effect="spotlight"
533	          rimSide="right"
534	          spotlightFilter="grayscale(100%) contrast(1.18) brightness(0.45)"
535	        >
536	          <img className={styles.bgImg} src="/theme_images/templefront-white.png" alt="" />
537	        </DynamicSvgEffect>
538	        <DynamicSvgEffect
539	          className={`${styles.bgArt} ${styles.bgElephant}`}
540	          effect="spotlight"
541	          rimSide="left"
542	          spotlightFilter="grayscale(100%) contrast(1.18) brightness(0.45)"
543	        >
544	          <img className={styles.bgImg} src="/theme_images/elephant-art-white.png" alt="" />
545	        </DynamicSvgEffect>
546	        <DynamicSvgEffect
547	          className={`${styles.bgArt} ${styles.bgSvgBand}`}
548	          effect="spotlight"
549	          rimSide="right"
550	          spotlightFilter="grayscale(100%) contrast(1.18) brightness(0.45)"
551	        >
552	          <img className={styles.bgImg} src="/theme_images/Godess-lakshmi-white.png" alt="" />
553	        </DynamicSvgEffect>
554	      </div>
555	
556	      <nav className={styles.crumbs} aria-label="Breadcrumb">
557	        <a href="/">Home</a>
558	        <span className={styles.sep}>/</span>
559	        <a href="/products">Products</a>
560	        <span className={styles.sep}>/</span>
561	        <span className={styles.here}>{product.title}</span>
562	      </nav>
563	
564	      <ErrorBoundary>
565	        <div className={styles.productGrid}>
566	          <div className={styles.leftCol}>
567	            <Gallery
568	              images={images}
569	              activeIdx={activeIdx}
570	              setActiveIdx={setActiveIdx}
571	              onOpenLightbox={(i) => setLightbox({ open: true, idx: i })}
572	              productTitle={product.title}
573	            />
574	            <MaterialStory className={styles.msDesktopOnly} />
575	          </div>
576	
577	          <div className={styles.info}>
578	            <div className={styles.eyebrow}>
579	              <span className={styles.eyebrowGlyph} /> Hand-Carved · Tadipatri Atelier
580	            </div>
581	            <h1 className={styles.productTitle}>{product.title}</h1>
582	            {product.subtitle && <p className={styles.subtitle}>{product.subtitle}</p>}
583	
584	            <div className={styles.ornamentDivider}>
585	              <span className={styles.dividerLine} />
586	              <span className={styles.dividerGlyph}>✦</span>
587	              <span className={styles.dividerLine} />
588	            </div>
589	
590	            <div className={styles.priceRow}>
591	              <span className={styles.price}>{fmt(product.price)}</span>
592	              {product.originalPrice && product.originalPrice > (product.price || 0) && (
593	                <>
594	                  <span className={styles.strike}>{fmt(product.originalPrice)}</span>
595	                  <span className={styles.savePill}>Save {savePct}%</span>
596	                </>
597	              )}
598	            </div>
599	
600	            <div className={styles.detailsBox}>
601	              {product.material && (
602	                <div className={styles.detailsRow}>
603	                  <span className={styles.detailsLabel}>Material</span>
604	                  <span className={styles.detailsValue}>{product.material}</span>
605	                </div>
606	              )}
607	              {product.dimensions && (
608	                <div className={styles.detailsRow}>
609	                  <span className={styles.detailsLabel}>Dimensions</span>
610	                  <span className={styles.detailsValue}>{product.dimensions}</span>
611	                </div>
612	              )}
613	              {product.weight != null && (
614	                <div className={styles.detailsRow}>
615	                  <span className={styles.detailsLabel}>Weight</span>
616	                  <span className={styles.detailsValue}>
617	                    {product.weight} {product.weightUnit || 'g'}
618	                  </span>
619	                </div>
620	              )}
621	              <div className={styles.detailsRow}>
622	                <span className={styles.detailsLabel}>Availability</span>
623	                <span className={`${styles.stock} ${!product.inStock ? styles.stockOut : ''}`}>
624	                  <span className={`${styles.stockDot} ${!product.inStock ? styles.stockDotOut : ''}`} />
625	                  {product.inStock ? 'In Stock' : 'Out of Stock'}
626	                </span>
627	              </div>
628	            </div>
629	
630	            <MaterialStory className={styles.msMobileOnly} />
631	
632	            {product.description && <Description text={product.description} />}
633	
634	            <div className={`${styles.buyBox} ${styles.buyBoxSticky}`}>
635	              <div className={styles.qtyRow}>
636	                <span className={styles.qtyLabel}>Quantity</span>
637	                <div className={styles.qty}>
638	                  <button onClick={() => setQty(q => Math.max(1, q - 1))} disabled={qty <= 1} aria-label="Decrease quantity">
639	                    <MinusI />
640	                  </button>
641	                  <span className={styles.qtyValue}>{qty}</span>
642	                  <button onClick={() => setQty(q => Math.min(10, q + 1))} disabled={qty >= 10} aria-label="Increase quantity">
643	                    <PlusI />
644	                  </button>
645	                </div>
646	              </div>
647	              <p className={styles.shipNote}>Free shipping on orders over $50</p>
648	              <div className={styles.actions}>
649	                <button
650	                  className={styles.cta}
651	                  onClick={handleAddToCart}
652	                  disabled={!product.inStock || state.isAddingToCart || cartLoading}
653	                >
654	                  {(state.isAddingToCart || cartLoading) ? (
655	                    <>
656	                      <LoadingSpinner size="small" color="white" />
657	                      <span>Adding…</span>
658	                    </>
659	                  ) : !product.inStock ? (
660	                    <span>Out of Stock</span>
661	                  ) : (
662	                    <>
663	                      <ChiselI />
664	                      <span>Add to Cart</span>
665	                    </>
666	                  )}
667	                </button>
668	                <button
669	                  className={`${styles.wish} ${inWishlist ? styles.wishActive : ''}`}
670	                  aria-label={inWishlist ? 'Remove from wishlist' : 'Add to wishlist'}
671	                  disabled={wishlistBusy}
672	                  onClick={async () => {
673	                    if (!rawProduct) return;
674	                    if (!wishAuth) { window.location.href = '/login'; return; }
675	                    await toggleWishlist(rawProduct.id);
676	                  }}
677	                >
678	                  <HeartI filled={inWishlist} />
679	                </button>
680	              </div>
681	              {state.addToCartSuccess && (
682	                <div className={`${styles.feedback} ${styles.feedbackSuccess}`}>Added to cart</div>
683	              )}
684	              {state.addToCartError && (
685	                <div className={`${styles.feedback} ${styles.feedbackError}`}>{state.addToCartError}</div>
686	              )}
687	            </div>
688	          </div>
689	        </div>
690	
691	        <CraftStrip />
692	
693	        <div className={styles.reviewsWrap}>
694	          {/* Demoing the empty state by passing an explicit []. Drop the
695	              prop (or pass real reviews) to switch to the populated view. */}
696	          <Reviews reviews={[]} />
697	        </div>
698	
699	        <div className={styles.similarWrap}>
700	          <SimilarProductsSection current={product} />
701	        </div>
702	      </ErrorBoundary>
703	
704	      <Lightbox
705	        open={lightbox.open}
706	        idx={lightbox.idx}
707	        images={images}
708	        onClose={() => setLightbox(s => ({ ...s, open: false }))}
709	        onPrev={() => setLightbox(s => ({ ...s, idx: (s.idx - 1 + images.length) % images.length }))}
710	        onNext={() => setLightbox(s => ({ ...s, idx: (s.idx + 1) % images.length }))}
711	      />
712	    </div>
713	  );
714	}
