/* BUY BOX — header glass parity. Three stacked backdrop-blurs: the box's
   own blur(12px), plus two inner layers (z-0 distortion via #glass-distortion
   from Header.tsx, z-1 white tint at blur(2px)). Don't collapse these — the
   turbulence layer needs its own lightly-blurred surface to distort. */
.buyBox {
  position: relative;
  isolation: isolate;
  border-radius: 18px;
  border: 1.5px solid rgba(229, 232, 235, 0.5);
  background: transparent;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1), 0 6px 6px rgba(0, 0, 0, 0.05);
  overflow: hidden;
  padding: 1.1rem 1.25rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  margin-top: 1rem;
}
.buyBox::before {
  content: '';
  position: absolute;
  inset: 0;
  z-index: 0;
  border-radius: inherit;
  backdrop-filter: blur(2px);
  -webkit-backdrop-filter: blur(2px);
  filter: url(#glass-distortion);
  pointer-events: none;
}
.buyBox::after {
  content: '';
  position: absolute;
  inset: 0;
  z-index: 1;
  border-radius: inherit;
  background-color: rgba(255, 255, 255, 0.25);
  backdrop-filter: blur(2px);
  -webkit-backdrop-filter: blur(2px);
  pointer-events: none;
}
.buyBox > .qtyRow,
.buyBox > .shipNote,
.buyBox > .actions,
.buyBox > .feedback {
  position: relative;
  z-index: 2;
}
.buyBoxSticky {
  position: sticky;
  top: 6.5rem;
}

