/* Background art layer (scrolls with page) */
.pdpBg {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  overflow: hidden;
  /* Single radial-gradient mask feathers all four edges in one pass.
     The previous double-linear + mask-composite: intersect forced an
     extra compositor flatten on every scroll frame across the wrapper
     holding all 4 multiply-blended bg arts. Same edge-fade visual,
     one composite pass instead of two. */
  mask-image: radial-gradient(ellipse 96% 98% at 50% 50%, black 78%, transparent 100%);
  -webkit-mask-image: radial-gradient(ellipse 96% 98% at 50% 50%, black 78%, transparent 100%);
}
.pdp > :not(.pdpBg):not(.ornamentCorner) {
  position: relative;
  z-index: 1;
}
.pdpBg .bgArt {
  position: absolute;
  user-select: none;
  pointer-events: none;
  display: block;
}
.pdpBg .bgImg {
  width: 100%;
  display: block;
  pointer-events: none;
  user-select: none;
  /* DIM BASE — barely visible. Under mix-blend-mode: multiply on the wrapper,
     a pixel of brightness ~0.92 reads as a faint whisper on the cream paper.
     The spotlit COPY of the same img (cloned by DynamicSvgEffect) overrides
     this via inline style to a low-brightness/high-contrast filter, so the
     pool of light reveals the art crisply — and once the spotlight passes,
     the area drops back to this ghost state. */
  filter: grayscale(100%) brightness(0.94);
  opacity: 0.55;
  /* Soft elliptical vignette so the natural edges of each PNG fade into the
     page instead of clipping abruptly. Applies to both the base img and the
     cloned spotlit img inside the radial mask layer. */
  mask-image: radial-gradient(ellipse 92% 92% at 50% 50%, black 45%, transparent 100%);
  -webkit-mask-image: radial-gradient(ellipse 92% 92% at 50% 50%, black 45%, transparent 100%);
}

