/* ============================================================
   GALLERY — mosaic stack (signature)
   ============================================================ */
.gallery {
  position: relative;
  display: flex;
  flex-direction: column;
  gap: 1.5rem;
}
.mosaicStack {
  position: relative;
  aspect-ratio: 1 / 1;
  display: grid;
  place-items: center;
  perspective: 1200px;
  /* Allow vertical page scroll to pass through; horizontal gestures are
     captured by our pointer handlers for swipe-to-switch. */
  touch-action: pan-y;
  user-select: none;
  -webkit-user-select: none;
}
.mosCard {
  position: absolute;
  inset: 0;
  border-radius: 28px;
  overflow: hidden;
  border: 1px solid rgba(229, 232, 235, 0.6);
  background: #ffffff;
  box-shadow: 0 30px 60px -20px rgba(0, 0, 0, 0.25), 0 12px 30px -8px rgba(0, 0, 0, 0.15);
  transition: transform 0.55s var(--ease-out), opacity 0.4s var(--ease-soft), box-shadow 0.4s ease;
  transform-origin: center center;
}
.mosCardActive {
  box-shadow: 0 40px 80px -20px rgba(0, 0, 0, 0.35), 0 16px 40px -10px rgba(0, 0, 0, 0.2);
  cursor: zoom-in;
  /* Promote only the active card to its own GPU layer — non-active cards
     don't move per-frame, so they don't need permanent layer allocation. */
  will-change: transform;
}
.mosCard img {
  width: 100%;
  height: 100%;
