/* BUY BOX — header glass parity. Three stacked backdrop-blurs: the box's
   own blur(12px), plus two inner layers (z-0 distortion via #glass-distortion
   from Header.tsx, z-1 white tint at blur(2px)). Don't collapse these — the
   turbulence layer needs its own lightly-blurred surface to distort. */
.buyBox {
  position: relative;
  border-radius: 18px;
  border: 1.5px solid rgba(229, 232, 235, 0.5);
  background: transparent;
  backdrop-filter: blur(12px);
  -webkit-backdrop-filter: blur(12px);
  box-shadow: 0 8px 32px rgba(0, 0, 0, 0.1), 0 6px 6px rgba(0, 0, 0, 0.05);
  overflow: hidden;
  padding: 1.1rem 1.25rem;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
  margin-top: 1rem;
}
/* Inner glass layers — real DOM siblings, mirroring Header.tsx exactly.
   `isolation: isolate` belongs ONLY on the SVG-filter layer (so the
   distortion is contained), NOT on the outer .buyBox — that would trap
   the tint layer's backdrop sampling and kill the frosted look. */
