  position: absolute;
  inset: 0;
  z-index: 0;
  border-radius: inherit;
  backdrop-filter: blur(2px);
  -webkit-backdrop-filter: blur(2px);
  filter: url(#glass-distortion);
  isolation: isolate;
  pointer-events: none;
}
.buyBoxTint {
  position: absolute;
  inset: 0;
  z-index: 1;
  border-radius: inherit;
  background-color: rgba(255, 255, 255, 0.25);
  backdrop-filter: blur(2px);
  -webkit-backdrop-filter: blur(2px);
  pointer-events: none;
}

